example.bad:
def appt_creation_failed_error(error: nil, title: nil, detail: nil, status: nil)
  {
    errors: [{
      title: title || 'Appointment creation failed',
      detail: detail || 'Could not create appointment',
      meta: {
        original_detail: error.try(:response_values)&.dig(:detail),
        original_error: error.try(:message) || 'Unknown error',
        backend_response: error.try(:original_body)
        # original_body is the RAW upstream HTTP response body
        # If upstream echoes veteran data in errors, it reaches the client
      }
    }]
  }
end

example.good:
def appt_creation_failed_error(error: nil, title: nil, detail: nil, status: nil)
  {
    errors: [{
      title: title || 'Appointment creation failed',
      detail: detail || 'Could not create appointment',
      meta: {
        error_class: error.class.name,
        code: error.respond_to?(:original_status) ? error.original_status : status
        # Only safe identifiers: class name and status code
        # No raw upstream body, no unsanitized message strings
      }
    }]
  }
end

example.bad:
def response_values
  {
    detail: extract_detail(@env.body),
    source: { vamf_url: anonymize_uri(@env.url), vamf_body: @env.body,
              vamf_status: @env.status }
  }
end
# vamf_body contains the raw upstream response; if this exception's
# response_values are rendered to the client, PII leaks

example.good:
def response_values
  {
    detail: extract_detail(@env.body),
    source: { vamf_url: anonymize_uri(@env.url),
              vamf_status: @env.status }
  }
end
# Raw body excluded from response_values; log it separately
# at error level with sanitization if needed for debugging
